// // This is a 1-to-2 demultiplexer that selects between two 4-bit outputs based on a single select line.
module mux2to1 (  
    input [3:0] A,  
    input [3:0] B,  
    input S,  
    output reg [3:0] Y  
);  
    always @(*) begin  
        if (S)  
            Y = B;  
        else  
            Y = A;  
    end  
endmodule
